body:
Hi,

I wrote a mixed-signal SystemVerilog model of a ring oscillator. It uses timescale 1s/1fs. The period of the oscillator is about 1ns, but it takes about 20s wall clock time to simulate the whole testbench of 3ns.

From the print messages, we can see from 0ns ~ 2ns, it is very fast. But in 2ns ~ 3ns, it takes most of the wall clock time.

The detailed information is as the following.

> Thanks for taking the time to report this.

> Can you attach an example that shows the issue?  (Must be openly licensed, ideally in test_regress format.)

Verilation command: `verilator --language 1800-2017 --top tb_osc --binary -j 0 -O3 --trace-fst --trace-threads 2 --threads 16 --assert -DSIMULATION --autoflush --prof-cfuncs bhv_dco.sv tb_osc.sv`

Run command: `./obj_dir/Vtb_osc`

`tb_osc.sv`:

```systemverilog
module tb_osc;

timeunit 1s;
timeprecision 1fs;

// Keep this string identical to the module name
localparam string module_name = "tb_osc";

// ******************
// Signal Definitions
// ******************

logic dco_out;

// *****************
// Module Connection
// *****************

bhv_dco dco (
    // Inputs
    .coarse_cw(8.0),
    .medium_cw(8.0),
    .fine_cw(32.0),

    // Outputs
    .rf_out(dco_out)
);

// ******************
// Behavioral Stimuli
// ******************

initial fork
    $display("Start simulation and dump waveform to ", {module_name, ".fst"});
    for (;;) begin
        $display("Current time: %g", $realtime);
        #1ns;
    end
join

// Record waveform
initial begin
    $dumpfile({module_name, ".fst"});
    $dumpvars;
    #3ns $finish;
end

endmodule : tb_osc
```


`bhv_dco.sv`:

```systemverilog
module bhv_dco #(
    parameter string jitter_file_name = "dco_pn.txt",

    parameter realtime coarse_ofst = 600ps,
    parameter realtime coarse_res  = 60ps,
    parameter realtime medium_ofst = 130ps,
    parameter realtime medium_res  = 6ps,
    parameter realtime fine_ofst   = 70ps,
    parameter realtime fine_res    = 0.2ps
) (
    input real coarse_cw,
    input real medium_cw,
    input real fine_cw,
    output logic rf_out
);

timeunit 1s;
timeprecision 1fs;

// Construct jitter arrays

int fjitter, jitter_arr_size, jitter_pos;
realtime jitter_arr[];

initial begin
    fjitter = $fopen(jitter_file_name, "r");
    $fscanf(fjitter, "%d", jitter_arr_size);
    jitter_arr = new[jitter_arr_size];
    jitter_pos = 0;

    for (int i=0; i<jitter_arr_size; i++) begin
        $fscanf(fjitter, "%g", jitter_arr[i]);
    end
end

// Delay calculation

realtime coarse_delay, medium_delay, fine_delay, jitter;

assign coarse_delay = 0.5 * (coarse_cw * coarse_res + coarse_ofst         );
assign medium_delay = 0.5 * (medium_cw * medium_res + medium_ofst         );
assign   fine_delay = 0.5 * (  fine_cw *   fine_res +   fine_ofst + jitter);

assign jitter = jitter_arr[jitter_pos];

// Circuit connection

logic coarse_out, medium_out, fine_out;

// Use transport delay to model the delay of the coarse bank, which is
// constructed by logic gate delays.
initial coarse_out = 0;
always @ (fine_out) coarse_out <= #coarse_delay ~fine_out;

// Use inertial delay to model medium and fine banks, which are RC delays.
assign #medium_delay medium_out = ~coarse_out;
assign #fine_delay   fine_out   = ~medium_out;

// Trigger jitter array
always @ (posedge coarse_out)
    jitter_pos <= jitter_pos >= jitter_arr_size - 1 ? 0 : jitter_pos + 1;

// Final output
assign #50ps rf_out = fine_out;

endmodule : bhv_dco

```

